INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1045", 10, 1, 7, 12300101, 20, 1, 3.74, 1, 3001, "はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1046", 0, 9, 1, 12300102, 20, 1, 3.85, 1, 3001, "なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1047", 8, 5, 5, 12300103, 20, 1, 0.01, 1, 3001, "すごい点数ね…！\nあんた勉強してないとか言って\nホントはめちゃくちゃやってる\nパターンのやつね！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1048", 4, 7, 8, 12300104, 20, 1, 2.86, 2, 3001, "勉強の成果、\nちゃんとでてんじゃない！\nあたしもあんたの先生として、\n鼻が高いわ～♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1049", 9, 3, 5, 12300105, 20, 1, 2.02, 2, 3001, "オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1050", 0, 1, 5, 12300106, 20, 1, 4.46, 2, 3001, "難しい問題を選んだつもりなのに\nすごい正解数ね…！\nでもまだ上がある…\n次は最難関に挑戦よ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1051", 7, 4, 5, 12300107, 20, 1, 6.85, 3, 3001, "すごいすごいとは思ってたけど、\nあんた勉強も完璧なの…？\nそりゃみんなあんたに惚れ…\nや、な、なんでもない！！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1052", 0, 9, 5, 12300108, 20, 1, 3.79, 3, 3001, "この問題、あたしでも悩む\n超難問なのに…\nふふっ、もう褒めるしかないわ！\n大変よくできました！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1053", 7, 4, 4, 12300109, 20, 1, 0.01, 3, 3001, "別に顔赤くなんてなってない！\n頭がいい人が好きとか…\nかっこいいとか…\n…思ってないからね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1054", 0, 5, 5, 12300110, 20, 1, 0.0, 1, 3001, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1054", 0, 5, 5, 12300112, 20, 1, 0.0, 2, 3001, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, "vo_minigame_1012_result_1054", 0, 5, 5, 12300114, 20, 1, 0.0, 3, 3001, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1056", 10, 7, 5, 12300116, 15, 1, 3.0, 1, 3001, "おお～かなり正解できてるわね！\nこの調子でもっとすごい点\n目指しちゃうわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1057", 10, 8, 8, 12300117, 15, 1, 0.01, 1, 3001, "うん、バッチリいい感じよ！\nちゃんと勉強してるみたいで\n関心関心♪");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1058", 0, 8, 5, 12300118, 15, 1, 4.01, 1, 3001, "え、こんなにいい点取れたのに\nまだ満足してないの？\nなによその向上心…\nいいじゃない！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1059", 10, 7, 8, 12300119, 15, 1, 2.83, 2, 3001, "スピードも正解数もいい感じよ！\nねえねえ、この調子で\nてっぺん目指しちゃう？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1060", 0, 10, 10, 12300120, 15, 1, 0.0, 2, 3001, "この難易度でも\nスラスラ答えちゃうなんて…\nあんたって\nほんとすごいやつよね…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1061", 4, 7, 8, 12300121, 15, 1, 3.66, 2, 3001, "これだけ正解できたら\n勉強も楽しいわよね♪\nさ、まだまだ続けるわよ～！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1062", 0, 8, 5, 12300122, 15, 1, 3.28, 3, 3001, "あんた、この成績\nまぐれじゃないわよね…！\nこれだけできたら\n大したもんだわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1063", 0, 1, 8, 12300123, 15, 1, 2.7, 3, 3001, "すごい！　とってもいい成績よ！\nこの難問も、あんたにかかりゃ\nイチコロってやつ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 2, "vo_minigame_1012_result_1064", 9, 9, 5, 12300124, 15, 1, 3.98, 3, 3001, "あんた…もしかして\nあたしより点数いいかも？\nあ、あたしもあんたを見習って\n勉強しないとね…！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1067", 0, 1, 7, 12300131, 10, 1, 2.51, 1, 3001, "うん、なかなかいい点数よ！\nでもまだまだ頑張れるわよね？\nはい、次いきましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1068", 0, 7, 1, 12300132, 10, 1, 4.16, 1, 3001, "十分優秀な成績だけど\nあんたならもっとできる！\nさ、頑張って勉強するわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1069", 0, 7, 8, 12300133, 10, 1, 2.07, 1, 3001, "うん、いい感じね！\nこの調子で少しずつ、\n正解数を増やしてくわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1070", 0, 1, 8, 12300134, 10, 1, 3.51, 2, 3001, "難問揃いなのに、\nけっこーいい感じじゃない！\nちゃんとできてるから\n自信もっていいわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1071", 0, 1, 1, 12300135, 10, 1, 0.0, 2, 3001, "難しい問題でも基礎は大事よ！\nこの調子でどんどん\n点数上げていきましょう！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1072", 0, 7, 1, 12300136, 10, 1, 4.3, 2, 3001, "10問以上取れてるわね！\nえ、まだ物足りない？\nフフ、じゃあもっと上\n目指しちゃう？");
