INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1074", 0, 9, 8, 12300138, 10, 1, 3.68, 3, 3001, "はいお疲れ～\nなかなか良い点数じゃない\n…あたしも勉強しないとね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, "vo_minigame_1012_result_1075", 0, 1, 5, 12300139, 10, 1, 3.34, 3, 3001, "おお～10問以上\n正解してんじゃない！\nあんたやっぱり\nただ者じゃないわね～");
