INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1078", 0, 7, 1, 12300146, 5, 1, 4.24, 1, 3001, "ふ～ん、まあまあの出来だわ\n悪くはないんだけど…あんたには\nもっともっと期待してるわ～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1079", 0, 1, 7, 12300147, 5, 1, 4.74, 1, 3001, "うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1080", 0, 1, 1, 12300148, 5, 1, 0.0, 1, 3001, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1081", 0, 1, 8, 12300149, 5, 1, 2.21, 2, 3001, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1082", 0, 1, 3, 12300150, 5, 1, 2.46, 2, 3001, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1083", 0, 1, 3, 12300151, 5, 1, 2.94, 2, 3001, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1084", 0, 1, 7, 12300152, 5, 1, 4.19, 3, 3001, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1085", 0, 1, 1, 12300153, 5, 1, 0.0, 3, 3001, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 2, "vo_minigame_1012_result_1086", 0, 1, 3, 12300154, 5, 1, 2.63, 3, 3001, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1087", 0, 1, 3, 12300155, 1, 1, 5.53, 1, 3001, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1088", 9, 3, 3, 12300156, 1, 1, 0.01, 1, 3001, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1089", 3, 1, 3, 12300157, 1, 1, 4.15, 1, 3001, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1090", 9, 9, 9, 12300158, 1, 1, 0.01, 2, 3001, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1091", 0, 1, 3, 12300159, 1, 1, 5.37, 2, 3001, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1092", 0, 1, 3, 12300160, 1, 1, 1.44, 2, 3001, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1093", 0, 3, 3, 12300161, 1, 1, 0.0, 3, 3001, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1094", 3, 9, 3, 12300162, 1, 1, 2.91, 3, 3001, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_1095", 0, 1, 5, 12300163, 1, 1, 2.61, 3, 3001, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1096", 1, 2, 4, 12300164, 0, 1, 3.63, 1, 3001, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1097", 1, 2, 6, 12300165, 0, 1, 4.16, 1, 3001, "はあ…自分で何点取ったか\n分かってるわよね～…？\n０点よ０点！　舐めてんの！？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1098", 6, 3, 3, 12300166, 0, 1, 0.01, 1, 3001, "うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1099", 0, 2, 6, 12300167, 0, 1, 5.75, 2, 3001, "ねえ、あんた本気でやったの？\nまさか適当にやるわけないわよね\n…分かった、\nもう一回チャレンジするのよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1100", 1, 2, 4, 12300168, 0, 1, 5.64, 2, 3001, "あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1101", 8, 4, 8, 12300169, 0, 1, 5.73, 2, 3001, "ちょっと待って採点ミスかも…\n…いや合ってるわね。はい０点\n…って０点！？\nふざけんなーー！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1102", 1, 3, 5, 12300170, 0, 1, 5.32, 3, 3001, "あらら…０点よ\nま、難しい問題だしね…\n…つっても０点は無いわ！\n一問くらい正解しなさいよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1103", 9, 9, 3, 12300171, 0, 1, 2.37, 3, 3001, "残念だけど０点よ\nま、まあ前向きにとらえるなら、\n今が底よ！　どん底！\nあとは上がってくだけね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_1104", 3, 1, 9, 12300172, 0, 1, 4.25, 3, 3001, "…かなり出来が悪いわね\n一旦休憩しましょうか？\nリフレッシュして頭切り替えて\nもう一度頑張りましょう！");
