INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_2090", 0, 3, 0, 22300158, 1, 2, 2.89, 2, 3001, "ちょっとずつ覚えれば\nおーけーっしょ！\nうちと一緒に\nベンキョーだね！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_2091", 0, 7, 0, 22300159, 1, 2, 5.45, 2, 3001, "うちベンキョー苦手でも\nヒデサイとベンキョー\nするのは好き！　だから\nもっかい教えてくれる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_2092", 3, 10, 4, 22300160, 1, 2, 4.29, 2, 3001, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_2093", 6, 8, 4, 22300161, 1, 2, 4.64, 3, 3001, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_2094", 0, 5, 9, 22300162, 1, 2, 3.14, 3, 3001, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 2, "vo_minigame_1012_result_2095", 0, 4, 7, 22300163, 1, 2, 6.59, 3, 3001, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2096", 0, 3, 3, 22300164, 0, 2, 0.0, 1, 3001, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2097", 5, 10, 9, 22300165, 0, 2, 2.2, 1, 3001, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2098", 6, 4, 4, 22300166, 0, 2, 0.01, 1, 3001, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2099", 3, 2, 6, 22300167, 0, 2, 2.8, 2, 3001, "え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2100", 6, 4, 9, 22300168, 0, 2, 3.22, 2, 3001, "むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2101", 11, 0, 4, 22300169, 0, 2, 2.1, 2, 3001, "０点だね…\nでも、へーきへーき\nリベンジしたら、結果オーライ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2102", 3, 2, 0, 22300170, 0, 2, 2.74, 3, 3001, "おやつ休憩して\nリベンジしよっ！\n甘いの食べたら、イケるっしょ！");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, "vo_minigame_1012_result_2103", 9, 9, 6, 22300171, 0, 2, 3.0, 3, 3001, "ヒデサイでも\nおにムズな感じ？\nじゃあ、このテスト\n誰も解けなくない？");
